INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-acfc4025-moex-00092', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「流行歌曲足以打動人心，獲得支持的主要原因，在於創作者與受眾之間 並不需要繁雜的手續與作業，便能『共構』出療癒人心的新意義。1950年 代戒嚴令的箝制下，除了船員、漁民外，臺灣大多數的民眾都難有離開陸 地的機會。在這種時代狀況下，如果我們不把港歌中的海／港視為實境， 而將之當作漂泊、不安、挫折、徬徨無助、遠行、離散的象徵，便能對於 港歌風潮的出現，獲得合乎社會發展邏輯的解釋。」 根據上文，下列選項何者最符合文意？', '["戒嚴時期的流行歌曲，往往需要繁雜的手續與作業，才能發行唱片", "具有療癒人心功用的歌曲，往往是符合社會發展邏輯而能賺人熱淚", "1950年代臺灣有大量的漁民、船員，是社會中堅，促進港歌風潮出現", "港歌情境衍伸為生活遭遇與感受的象徵，是其擴大影響力的重要因素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00093', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「一個成功的領導者必須先將自己降低為『僕人』，做出根植於愛的犧牲 奉獻，與部屬建立愛與信任，激勵團隊發揮最大的潛能，為達成共同目標 而奮戰不懈。」 根據上文，下列選項何者正確？', '["不以位高而自恃，願意與部屬同心協力以挑戰未來", "領導人的身段愈低愈得民心，對外行銷可無往不利", "以激發團隊每個人最大潛能為目標，共營團隊績效", "為部屬做牛做馬在所不惜，可換得部屬的忠心耿耿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00094', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「如果你關注與其他投資人一樣的投資機會、投資每個人都認為會成功的 新創，那你會有一定程度的成績。但是，如果你想從粗糲中找到鑽石，找 到可能帶來超額報酬、非常特殊的新創，你就必須去別人不關注的地方， 也就是要找別人低估或忽視的機會。」 根據上文，下列選項何者最符合文意？', '["注意市場趨勢追捧成功新創", "投資熱門的科技發展新產品", "留心尚未萌芽的前瞻新事業", "認識新創就是市場中的鑽石"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00095', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「在滑世代中，觀看電影比以往更容易，除了走進電影院外，還有許多影 音串流平臺，隨時可以跟世界接軌。雖然觀看管道變多，但不變的是那種 大家一起待在共同空間中，同看一部電影的『儀式感』。隨著電影情節的 高低起伏，我們一起經歷冒險、體驗苦難，最後一同成長，這種一起笑、 一起哭、一起驚呼、一起療癒的過程，雖然每個人都是獨立的個體，卻不 再感到寂寞。」 根據上文，作者認為一起看電影的「儀式感」最可能的意義在於：', '["讓滑世代的孩子從網路世界抽離，面對現實考驗", "透過共同的觀看經驗，可形成記憶與話題的連結", "善於運用影音串流平臺的便利，以豐富娛樂生活", "集體觀看以刺激實體影音消費，促進影視的發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00096', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「美國科幻小說家雷‧布萊得伯利建議我們：既要學習接納別人的排斥， 也要學習排斥別人的接納。布萊得伯利的話嚴厲但實在，教我們以一種正 確的態度面對評論。當追求掌聲變成一種欲望，創作動機自然就變成對掌 聲的追求，這對作品可能是一種傷害。有些人對我們說好話，不見得是因 為作品，還有其他複雜的理由，例如人情關係等等；內行人對作品發表意 見，也有各種理由，未必著眼於作品，而更在反應這位內行人的其他思維。 我們要拿出自己的『測謊器』，辨識那些評論對我們是有幫助的。我們經 常忽略：批評最嚴厲的人，其實是我們的恩人；說最多好話的人，可能在 無形中害了我們。」 根據上文，下列選項何者最符合文意？', '["沒有評論不含複雜動機", "各種評論都應虛心採信", "讚美的背後必藏著毒藥", "迎合眾人可能扭曲創作"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00097', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '承上題，下列何者最符合上文對「內行人」的觀察？', '["有可能藉別人的作品談其他想法", "有時會為追求掌聲而褒揚創作者", "往往毫不留情面地嚴厲批評作品", "常自詡專業而不接納別人的排斥"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00098', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「有一家醫院為提升服務品質，改善對病人的醫療照護，請國際知名顧問 公司來幫忙。管理顧問提出各種炫目的流程圖與昂貴的資訊系統方案。後 來，這家醫院又找了另一家設計顧問公司來評估。這家設計人員將錄影機 架在自己頭上，躺在床上模擬病人錄下一天所看到的世界。設計公司發現， 病人一天中，一半以上的時間看不到『人類』，只看到天花板。他們唯一 能看到人的時候，是護士用輪椅帶他們去進行各種檢驗。所以，要如何改 善對病人的服務？醫師與護士看完影片後，決定不導入昂貴的資訊系統。 他們先布置天花板，用色彩繽紛的圖畫點綴，也在入口處放一個大白板， 讓探病的人留言。然後，他們在輪椅上裝一個照後鏡，讓病人可以在行進 中、說話時看到護士的臉，就這麼提升了服務品質。」 第二間顧問公司獲選的最主要原因是：', '["能同時滿足醫護人員與病人的多方需求", "能用更有創意的方法，提升管理的成效", "能理解醫院想節省經費解決問題的心理", "能從病人的角度發現問題，並找到解方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00099', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '承上題，醫院改善服務品質的方式，不包括下列何者？', '["增加檢驗的次數讓病人更安心", "讓探病的人在入口白板上留言", "輪椅裝照後鏡增加與人的互動", "醫護人員花費心力布置天花板"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00100', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-35395ec3', 'sub-disabled-acfc4025-05', NULL, 'single_choice', '求A、B端的等效電阻R 為何？ T', '["10 Ω", "20 Ω", "30 Ω", "40 Ω"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "7fea4f88e3b6", "answer_pdf_sha1": "6883ea3d1fb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "1611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00101', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-35395ec3', 'sub-disabled-acfc4025-05', NULL, 'single_choice', '電阻的電導為0.2姆歐，當該電阻兩端的電壓為30伏特時，流過此電阻的 電流為何？', '["2安培", "4安培", "6安培", "8安培"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "7fea4f88e3b6", "answer_pdf_sha1": "6883ea3d1fb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "1611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL)
